const CDN_URL            = "https://raw.githubusercontent.com/ShahGCreator/icon/main/PNG/";
const ITEMS_PER_PAGE     = 80;
const SEARCH_DEBOUNCE_MS = 250;
const FIRST_BATCH        = 80;
const PARSE_CHUNK        = 2000;
const DEV_STORAGE_KEY    = "fflib_dev_mode";
const FAB_POS_KEY        = "fflib_fab_pos";

let iconsData      = [];
let filteredData   = [];
let currentPage    = 1;
let debounceTimer  = null;
let isLoading      = true;
let isDevMode      = false;
let selectedIds    = new Set();
let currentPageIds = [];
let pendingOpenId  = null;

const $   = id => document.getElementById(id);
const els = {};

const imgObserver = new IntersectionObserver((entries, obs) => {
  entries.forEach(entry => {
    if (!entry.isIntersecting) return;
    const img  = entry.target;
    const src  = img.dataset.src;
    const rare = img.dataset.rare || "COMMON";
    if (!src) return;
    const preload   = new Image();
    preload.onload  = () => {
      img.src = src;
      img.removeAttribute("data-src");
      img.parentElement?.querySelector(".img-shimmer")?.remove();
    };
    preload.onerror = () => {
      img.src = `/error/${rare}.png`;
      img.removeAttribute("data-src");
      img.parentElement?.querySelector(".img-shimmer")?.remove();
    };
    preload.src = src;
    obs.unobserve(img);
  });
}, { rootMargin: "150px" });

document.addEventListener("DOMContentLoaded", () => {
  els.search          = $("search");
  els.tagFilter       = $("tagFilter");
  els.typeFilter      = $("typeFilter");
  els.rareFilter      = $("rareFilter");
  els.grid            = $("iconGrid");
  els.pagination      = $("pagination");
  els.modal           = $("modal");
  els.devBtn          = $("devCopyBtn");
  els.devCount        = $("devCount");
  els.devToggle       = $("devToggle");
  els.settingsOverlay = $("settingsOverlay");

  const yr = $("settingsYear");
  if (yr) yr.textContent = new Date().getFullYear();

  isDevMode = false;
  applyDevMode();

  const urlParams = new URLSearchParams(location.search);
  const iidParam  = urlParams.get("iid") || "";
  if (iidParam) pendingOpenId = iidParam.trim();

  if (els.search) {
    els.search.addEventListener("keydown", e => {
      if (e.key === "Enter") {
        e.preventDefault();
        clearTimeout(debounceTimer);
        currentPage = 1;
        filterIcons();
      }
    });
    els.search.addEventListener("input", () => {
      const clean = els.search.value.replace(/[\r\n]/g, "");
      if (clean !== els.search.value) els.search.value = clean;
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => { currentPage = 1; filterIcons(); }, SEARCH_DEBOUNCE_MS);
    });
    els.search.addEventListener("paste", e => {
      e.preventDefault();
      const text  = (e.clipboardData || window.clipboardData).getData("text");
      const clean = text.replace(/[\r\n]+/g, " ").trim();
      document.execCommand("insertText", false, clean);
    });
  }
  document.addEventListener("keydown", e => {
     if (e.key === "Escape") closeModal();
  });

  ["tagFilter","typeFilter","rareFilter"].forEach(id => {
    const el = $(id);
    if (el) el.addEventListener("change", () => { currentPage = 1; filterIcons(); });
  });

  if (els.modal) {
    els.modal.addEventListener("click", e => { if (e.target === els.modal) closeModal(); });
  }

  const copyIdBtn = $("copyIdBtn");
  if (copyIdBtn) {
    copyIdBtn.addEventListener("click", () => {
      const id = $("modalItemId")?.textContent?.trim();
      if (id) copyToClipboard(id, copyIdBtn);
    });
  }

  const modalShareBtn = $("modalShareBtn");
  if (modalShareBtn) modalShareBtn.addEventListener("click", () => shareItem());

  const closeBtnEl = $("settingsCloseBtn");
  if (closeBtnEl) closeBtnEl.addEventListener("click", () => closeSettings());

  if (els.settingsOverlay) {
    els.settingsOverlay.addEventListener("click", e => {
      if (e.target === els.settingsOverlay) closeSettings();
    });
  }

  const shareRow = $("sharePageRow");
  if (shareRow) shareRow.addEventListener("click", shareCurrentPage);

  initFAB();
  startLoadingAnimation();
  fetchIconsStreamed();
});

function initFAB() {
  const fab = $("fabSettings");
  if (!fab) return;

  let dragging  = false;
  let startX, startY, startLeft, startTop;
  const SIZE   = 40;
  const THRESH = 8;

  try {
    const saved = JSON.parse(localStorage.getItem(FAB_POS_KEY) || "null");
    if (saved) {
      fab.style.right  = "auto";
      fab.style.bottom = "auto";
      fab.style.left   = clamp(saved.x, 0, window.innerWidth  - SIZE) + "px";
      fab.style.top    = clamp(saved.y, 0, window.innerHeight - SIZE) + "px";
    }
  } catch(e) {}

  fab.addEventListener("pointerdown", e => {
    dragging = false;
    startX   = e.clientX;
    startY   = e.clientY;
    const rect = fab.getBoundingClientRect();
    startLeft  = rect.left;
    startTop   = rect.top;
    fab.style.right      = "auto";
    fab.style.bottom     = "auto";
    fab.style.left       = startLeft + "px";
    fab.style.top        = startTop  + "px";
    fab.style.transition = "none";
    fab.setPointerCapture(e.pointerId);
  });

  fab.addEventListener("pointermove", e => {
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    if (!dragging && (Math.abs(dx) > THRESH || Math.abs(dy) > THRESH)) dragging = true;
    if (!dragging) return;
    fab.style.left = clamp(startLeft + dx, 0, window.innerWidth  - SIZE) + "px";
    fab.style.top  = clamp(startTop  + dy, 0, window.innerHeight - SIZE) + "px";
  });

  fab.addEventListener("pointerup", () => {
    fab.style.transition = "";
    const wasDragging = dragging;
    dragging = false;
    if (wasDragging) {
      try {
        localStorage.setItem(FAB_POS_KEY, JSON.stringify({
          x: parseFloat(fab.style.left),
          y: parseFloat(fab.style.top)
        }));
      } catch(e) {}
    }
  });

  fab.addEventListener("pointercancel", () => {
    fab.style.transition = "";
    dragging = false;
  });

  fab.addEventListener("contextmenu", e => e.preventDefault());

  fab.addEventListener("click", () => {
    if (!dragging) toggleSettings();
  });
}

function clamp(val, min, max) { return Math.min(Math.max(val, min), max); }

function toggleSettings() {
  if (!els.settingsOverlay) return;
  els.settingsOverlay.classList.toggle("open");
}

function closeSettings() {
  if (!els.settingsOverlay) return;
  els.settingsOverlay.classList.remove("open");
}

function onDevToggle(checked) {
  isDevMode = checked;
  selectedIds.clear();
  applyDevMode();
  if (!isLoading) renderIcons();
}

function applyDevMode() {
  if (els.devToggle) els.devToggle.checked = isDevMode;
  if (els.devBtn) {
    if (isDevMode) els.devBtn.classList.add("show");
    else           els.devBtn.classList.remove("show");
  }
}

function copyAllIds() {
  const ids = selectedIds.size > 0 ? [...selectedIds] : currentPageIds;
  if (!ids.length) return;
  copyToClipboard(ids.join(", "), $("devCopyBtn"));
   onDevToggle(false);
}

function shareCurrentPage() {
  const url    = buildShareURL(null);
  const status = $("sharePageStatus");
  copyToClipboard(url, null);
  if (status) {
    const origSVG = status.innerHTML;
    status.classList.add("copied");
    status.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>`;
    setTimeout(() => { status.classList.remove("copied"); status.innerHTML = origSVG; }, 1800);
  }
}

function shareItem() {
  const itemId = $("modalItemId")?.textContent?.trim();
  if (!itemId) return;
  copyToClipboard(buildShareURL(itemId), $("modalShareBtn"));
}

function buildShareURL(itemId) {
  const params = new URLSearchParams();
  if (itemId) {
    params.set("iid", itemId);
    const name = $("modalName")?.textContent?.trim()        || "";
    const icon = $("modalIconName")?.textContent?.trim()    || "";
    const desc = $("modalDescription")?.textContent?.trim() || "";
    if (name) params.set("iname", name);
    if (icon) params.set("iicon", icon);
    if (desc) params.set("idesc", desc);
  } else {
    const o = (els.tagFilter?.value  || "").toLowerCase();
    const t = (els.typeFilter?.value || "").toLowerCase();
    const r = (els.rareFilter?.value || "").toUpperCase();
    if (o) params.set("o", o);
    if (r) params.set("r", r);
    if (t) params.set("t", t);
    const q = (els.search?.value || "").toLowerCase().trim();
    if (q) params.set("q", q);
    if (currentPage > 1) params.set("p", currentPage);
  }
  return `${location.origin}${location.pathname}?${params}`;
}

function copyToClipboard(text, btn) {
  const done = () => {
    if (!btn) return;
    const orig       = btn.innerHTML;
    const isDevBtn   = btn.classList.contains("dev-copy-btn");
    const isShareBtn = btn.classList.contains("modal-share-btn");
    if (isDevBtn) {
      btn.innerHTML = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Copied!`;
    } else if (isShareBtn) {
      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Copied`;
    } else {
      btn.innerHTML = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>`;
    }
    btn.classList.add("copied");
    setTimeout(() => { btn.innerHTML = orig; btn.classList.remove("copied"); }, 1800);
  };
  if (navigator.clipboard) {
    navigator.clipboard.writeText(text).then(done).catch(() => fallbackCopy(text, done));
  } else {
    fallbackCopy(text, done);
  }
}

function fallbackCopy(text, cb) {
  const ta = document.createElement("textarea");
  ta.value = text;
  ta.style.cssText = "position:fixed;opacity:0;top:0;left:0;";
  document.body.appendChild(ta);
  ta.select();
  try { document.execCommand("copy"); } catch(e) {}
  document.body.removeChild(ta);
  if (cb) cb();
}

async function fetchIconsStreamed() {
    showSkeletonGrid(FIRST_BATCH);

    const myWorker = new Worker('/w.min.js');

    try {
        const response = await fetch("/data.msgpack.gz");
        if (!response.ok) throw new Error("Fetch failed: " + response.status);

        const buffer = await response.arrayBuffer();

        myWorker.postMessage(buffer, [buffer]);

        myWorker.onmessage = async function(e) {
            if (e.data.success) {
                const data = e.data.data;
                await processInChunks(data);
                readQueryParams();
                if (pendingOpenId) {
                    tryOpenPendingItem();
                } else {
                    filterIcons();
                }
            } else {
                console.error("Worker Error:", e.data.error);
                showErrorState(els.grid);
            }
            myWorker.terminate();
        };

        myWorker.onerror = function(err) {
            console.error("Worker generic error:", err);
            myWorker.terminate();
        };

    } catch(err) {
        myWorker.terminate();
        console.error("fetchIconsStreamed error:", err);
        showErrorState(els.grid);
        if (els.pagination) els.pagination.style.display = "none";
    }
}

function processInChunks(data) {
  return new Promise(resolve => {
    let i = 0;
    function nextChunk() {
      const end = Math.min(i + PARSE_CHUNK, data.length);
      for (; i < end; i++) {
        const item = data[i];
        const id   = item.itemID || "";
        const rare = (item.Rare || "COMMON").toUpperCase();
        iconsData.push({
          itemId:      id || "Unknown ID",
          name:        item.name        || "Name Not Found",
          iconName:    item.icon        || "No Icon",
          tag:         (item.tag        || "").toLowerCase(),
          type:        (item.type       || "").toLowerCase(),
          rare,
          description: item.description || "No Description",
          imageUrl:    id ? `${CDN_URL}${id}.png` : `/error/${rare}.png`,
          _search: [
            item.name||"", id, item.icon||"",
            item.description||"", item.tag||"", item.type||"", rare
          ].join(" ").toLowerCase()
        });
      }
      if (i >= FIRST_BATCH && isLoading) {
        isLoading    = false;
        filteredData = [...iconsData];
        renderIcons();
      }
      if (i < data.length) requestAnimationFrame(nextChunk);
      else resolve();
    }
    requestAnimationFrame(nextChunk);
  });
}

function showSkeletonGrid(count = ITEMS_PER_PAGE) {
  if (!els.grid) return;
  const frag = document.createDocumentFragment();
  for (let i = 0; i < count; i++) {
    const card  = document.createElement("div");
    card.className = "icon-card skeleton";
    const inner = document.createElement("div");
    inner.className = "skeleton-img shimmer";
    card.appendChild(inner);
    frag.appendChild(card);
  }
  els.grid.innerHTML = "";
  els.grid.appendChild(frag);
  if (els.pagination) els.pagination.style.display = "none";
}

function filterIcons() {
  if (isLoading) return;
  const query        = (els.search?.value     || "").toLowerCase().trim();
  const selectedTag  = (els.tagFilter?.value  || "").toLowerCase();
  const selectedType = (els.typeFilter?.value || "").toLowerCase();
  const selectedRare = (els.rareFilter?.value || "").toUpperCase();

  filteredData = iconsData.filter(icon => {
    if (query        && !icon._search.includes(query)) return false;
    if (selectedTag  && icon.tag  !== selectedTag)     return false;
    if (selectedType && icon.type !== selectedType)    return false;
    if (selectedRare && icon.rare !== selectedRare)    return false;
    return true;
  });

  const totalPages = Math.ceil(filteredData.length / ITEMS_PER_PAGE) || 1;
  if (currentPage > totalPages) currentPage = 1;

  selectedIds.clear();
  updateURL();
  renderIcons();
}

function tryOpenPendingItem() {
  if (!pendingOpenId) return;
  const targetId = pendingOpenId;
  pendingOpenId  = null;

  let item = iconsData.find(i => i.itemId === targetId);

  if (!item) {
    const up   = new URLSearchParams(location.search);
    const name = up.get("iname") || "";
    const icon = up.get("iicon") || "";
    const desc = up.get("idesc") || "";
    if (name || icon || desc) {
      item = {
        itemId:      targetId,
        name:        name || "Item #" + targetId,
        iconName:    icon || "",
        description: desc || "",
        imageUrl:    `${CDN_URL}${targetId}.png`,
        rare:        "COMMON"
      };
    }
  }

  if (!item) return;

  if (els.search) els.search.value = "";
  filteredData = [...iconsData];
  currentPage  = 1;
  history.replaceState(null, "", location.pathname);
  renderIcons();

  setTimeout(() => {
    openModal(item.name, item.itemId, item.iconName, item.description, item.imageUrl, item.rare);
  }, 650);
}

function renderIcons() {
  const start   = (currentPage - 1) * ITEMS_PER_PAGE;
  const visible = filteredData.slice(start, start + ITEMS_PER_PAGE);

  currentPageIds = visible.map(i => i.itemId);
  if (els.devCount) els.devCount.textContent = currentPageIds.length;

  els.grid.querySelectorAll("img[data-src]").forEach(img => imgObserver.unobserve(img));

  if (!visible.length) {
    showErrorState(els.grid);
    if (els.pagination) els.pagination.style.display = "none";
    return;
  }

  if (els.pagination) els.pagination.style.display = "flex";

  const frag = document.createDocumentFragment();
  visible.forEach(icon => {
    const card = document.createElement("div");
    card.className = "icon-card";
    if (isDevMode && selectedIds.has(icon.itemId)) card.classList.add("dev-selected");

    const wrap    = document.createElement("div");
    wrap.className = "img-wrap";

    const shimmer = document.createElement("div");
    shimmer.className = "img-shimmer shimmer";

    const img = document.createElement("img");
    img.alt          = icon.name;
    img.decoding     = "async";
    img.dataset.src  = icon.imageUrl;
    img.dataset.rare = icon.rare;
    img.src = "data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7";

    imgObserver.observe(img);
    wrap.appendChild(shimmer);
    wrap.appendChild(img);
    card.appendChild(wrap);

    card.addEventListener("contextmenu", e => e.preventDefault());

    card.addEventListener("click", () => {
      if (isDevMode) {
        if (selectedIds.has(icon.itemId)) {
          selectedIds.delete(icon.itemId);
          card.classList.remove("dev-selected");
        } else {
          selectedIds.add(icon.itemId);
          card.classList.add("dev-selected");
        }
        const span = els.devBtn?.querySelector("span");
        if (span) {
          span.textContent = selectedIds.size > 0
            ? `${selectedIds.size} Selected`
            : currentPageIds.length;
        }
        const ids = selectedIds.size > 0 ? [...selectedIds] : currentPageIds;
        copyToClipboard(ids.join(", "), null);
      } else {
        openModal(icon.name, icon.itemId, icon.iconName, icon.description, icon.imageUrl, icon.rare);
      }
    });

    frag.appendChild(card);
  });

  els.grid.innerHTML = "";
  els.grid.appendChild(frag);
  updatePagination();
}

function updatePagination() {
  if (!els.pagination) return;
  const total = Math.ceil(filteredData.length / ITEMS_PER_PAGE);
  const frag  = document.createDocumentFragment();
  for (let i = 1; i <= total; i++) {
    const btn = document.createElement("button");
    btn.textContent = i;
    if (i === currentPage) btn.classList.add("active");
    btn.addEventListener("click", () => {
      currentPage = i;
      selectedIds.clear();
      updateURL();
      renderIcons();
      window.scrollTo({ top: 130, behavior: "smooth" });
    });
    frag.appendChild(btn);
  }
  els.pagination.innerHTML = "";
  els.pagination.appendChild(frag);
}

function updateURL() {
  const params = new URLSearchParams();
  const q = (els.search?.value     || "").toLowerCase().trim();
  const o = (els.tagFilter?.value  || "").toLowerCase();
  const t = (els.typeFilter?.value || "").toLowerCase();
  const r = (els.rareFilter?.value || "").toUpperCase();
  if (o)               params.set("o", o);
  if (currentPage > 1) params.set("p", currentPage);
  if (r)               params.set("r", r);
  if (t)               params.set("t", t);
  if (q)               params.set("q", q);
  history.replaceState(null, "", `${location.pathname}?${params}`);
}

function readQueryParams() {
  const p = new URLSearchParams(location.search);
  if (p.get("iid")) return;
  currentPage = parseInt(p.get("p")) || 1;
  const q = p.get("q") || "";
  if (els.search) els.search.value = q;
  setSelectValue(els.tagFilter,  p.get("o") || "");
  setSelectValue(els.typeFilter, p.get("t") || "");
  setSelectValue(els.rareFilter, p.get("r") || "", true);
}

function setSelectValue(select, value, upper = false) {
  if (!select || !value) return;
  const v = upper ? value.toUpperCase() : value.toLowerCase();
  for (const opt of select.options) {
    if ((upper ? opt.value.toUpperCase() : opt.value.toLowerCase()) === v) {
      select.value = opt.value; return;
    }
  }
  const opt = document.createElement("option");
  opt.value = upper ? v : value;
  opt.textContent = opt.value;
  select.appendChild(opt);
  select.value = opt.value;
}

function openModal(name, itemId, iconName, description, imageUrl, rare) {
  if (!els.modal) return;

  const modalImg     = $("modalImage");
  const modalShimmer = $("modalShimmer");

  if (modalShimmer) modalShimmer.style.display = "block";
  modalImg.classList.add("loading");
  modalImg.src = "data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7";

  $("modalName").textContent        = name        || "No Name";
  $("modalItemId").textContent      = itemId      || "No ID";
  $("modalIconName").textContent    = iconName    || "No Icon Name";
  $("modalDescription").textContent = description || "No Description";

  els.modal.classList.add("open");

  const preload   = new Image();
  preload.onload  = () => {
    modalImg.src = imageUrl;
    modalImg.classList.remove("loading");
    if (modalShimmer) modalShimmer.style.display = "none";
  };
  preload.onerror = () => {
    modalImg.src = `/error/${rare || "COMMON"}.png`;
    modalImg.classList.remove("loading");
    if (modalShimmer) modalShimmer.style.display = "none";
  };
  preload.src = imageUrl || `/error/${rare || "COMMON"}.png`;
}

function closeModal() {
  if (els.modal) els.modal.classList.remove("open");
}

function showErrorState(grid) {
  const year = new Date().getFullYear();
  grid.innerHTML = `
    <div class="no-items">
      <div class="no-items-icon">🔍</div>
      <h2>No Items Found</h2>
      <p class="sub">Nothing matches your search or filter.</p>
      <div class="divider"></div>
      <p class="connect-text">Follow ShahGCreator</p>
      <div class="social-links">
        <a href="https://www.youtube.com/@ShahGCreator" target="_blank"><img src="/icons/yt.svg" alt="YouTube"><span>YouTube</span></a>
        <a href="https://t.me/ShahGCreator" target="_blank"><img src="/icons/tg.svg" alt="Telegram"><span>Telegram</span></a>
        <a href="https://facebook.com/@ShahGCreator" target="_blank"><img src="/icons/fb.svg" alt="Facebook"><span>Facebook</span></a>
        <a href="https://instagram.com/ShahGCreator" target="_blank"><img src="/icons/ig.svg" alt="Instagram"><span>Instagram</span></a>
      </div>
      <div class="footer">© ShahGCreator ${year}</div>
    </div>`;
}

function updateLoadBar(fraction) {
  const bar     = $("loadingBar");
  const percent = $("loadingPercentage");
  if (bar)     bar.style.width     = Math.floor(fraction * 100) + "%";
  if (percent) percent.textContent = Math.floor(fraction * 100) + "%";
}

function startLoadingAnimation() {
  const overlay   = $("loadingOverlay");
  const header    = $("header");
  const container = $("container");
  const spinner   = $("loadingSpinner");
  if (!overlay) return;

  let progress  = 0;
  let completed = false;

  function tick() {
    if (!completed) {
      if (progress < 30) progress += 0.8;
      else if (progress < 60) progress += 0.4;
      else if (progress < 85) progress += 0.15;
      else if (progress < 95) progress += 0.05;
    } else {
      progress += 2;
    }
    if (progress > 100) progress = 100;
    updateLoadBar(progress / 100);
    if (progress < 100) {
      requestAnimationFrame(tick);
    } else {
      overlay.style.display = "none";
      if (header) header.style.display = "block";
      if (container) container.style.display = "block";
      if (spinner) spinner.style.display = "none";
    }
  }
  requestAnimationFrame(tick);
  function waitAndHide() {
    const hasCards = els.grid?.querySelector(".icon-card:not(.skeleton)");
    if (hasCards) {
      completed = true;
    } else {
      requestAnimationFrame(waitAndHide);
    }
  }
  requestAnimationFrame(waitAndHide);
}
